<script setup lang="ts">import { INQUIRY_PRIORITIES, INQUIRY_STATUSES, type AdminInquiryListQuery } from '@/types/inquiryAdmin'; const model=defineModel<AdminInquiryListQuery>({ required:true }); const emit=defineEmits<{ apply: [] }>()</script><template><form class="filters" @submit.prevent="emit('apply')"><label>Status<select v-model="model.status"><option value="all">All</option><option v-for="status in INQUIRY_STATUSES" :key="status" :value="status">{{ status }}</option></select></label><label>Priority<select v-model="model.priority"><option value="all">All</option><option v-for="priority in INQUIRY_PRIORITIES" :key="priority" :value="priority">{{ priority }}</option></select></label><label>Category<input v-model="model.category" placeholder="product, support" /></label><label>Search<input v-model="model.search" placeholder="title, message, nickname" /></label><button type="submit">Apply filters</button></form></template><style scoped>.filters{display:grid;grid-template-columns:repeat(5,minmax(140px,1fr));gap:12px;align-items:end;margin:20px 0}label{display:grid;gap:6px;font-size:12px;font-weight:750;color:rgba(36,31,26,.72)}input,select{min-height:38px;border:1px solid rgba(36,31,26,.16);border-radius:12px;background:rgba(255,255,255,.78);padding:0 11px;color:#241f1a}button{min-height:40px;border:0;border-radius:14px;background:#241f1a;color:#fff;font-weight:800;cursor:pointer}@media(max-width:980px){.filters{grid-template-columns:1fr 1fr}}@media(max-width:620px){.filters{grid-template-columns:1fr}}</style>
